UserControl.Resources.MotionClip:
@sequence
{
    @parallel
    {
        @animate with Tween(80ms)
        {
            @from
            {
                $PipelineRelay.Opacity = current;
                $PipelineInput.Opacity = current;
                $PipelineState.Opacity = current;
                $PipelineMeasure.Opacity = current;
                $PipelineArrange.Opacity = current;
                $PipelineCache.Opacity = current;
                $PipelineHit.Opacity = current;
                $PipelineBackend.Opacity = current;
            }
            @to
            {
                $PipelineRelay.Opacity = 0.24;
                $PipelineInput.Opacity = 0.24;
                $PipelineState.Opacity = 0.24;
                $PipelineMeasure.Opacity = 0.24;
                $PipelineArrange.Opacity = 0.24;
                $PipelineCache.Opacity = 0.24;
                $PipelineHit.Opacity = 0.24;
                $PipelineBackend.Opacity = 0.24;
            }
        }
        @animate with Tween(80ms)
        {
            @from
            {
                $PipelineRelay.Scale = current;
                $PipelineInput.Scale = current;
                $PipelineState.Scale = current;
                $PipelineMeasure.Scale = current;
                $PipelineArrange.Scale = current;
                $PipelineCache.Scale = current;
                $PipelineHit.Scale = current;
                $PipelineBackend.Scale = current;
            }
            @to
            {
                $PipelineRelay.Scale = 0.94;
                $PipelineInput.Scale = 0.94;
                $PipelineState.Scale = 0.94;
                $PipelineMeasure.Scale = 0.94;
                $PipelineArrange.Scale = 0.94;
                $PipelineCache.Scale = 0.94;
                $PipelineHit.Scale = 0.94;
                $PipelineBackend.Scale = 0.94;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineRelay.Opacity = 0.24;
            }
            @to
            {
                $PipelineRelay.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineRelay.Scale = 0.94;
            }
            @to
            {
                $PipelineRelay.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineInput.Opacity = 0.24;
            }
            @to
            {
                $PipelineInput.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineInput.Scale = 0.94;
            }
            @to
            {
                $PipelineInput.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineState.Opacity = 0.24;
            }
            @to
            {
                $PipelineState.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineState.Scale = 0.94;
            }
            @to
            {
                $PipelineState.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineMeasure.Opacity = 0.24;
            }
            @to
            {
                $PipelineMeasure.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineMeasure.Scale = 0.94;
            }
            @to
            {
                $PipelineMeasure.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineArrange.Opacity = 0.24;
            }
            @to
            {
                $PipelineArrange.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineArrange.Scale = 0.94;
            }
            @to
            {
                $PipelineArrange.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineCache.Opacity = 0.24;
            }
            @to
            {
                $PipelineCache.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineCache.Scale = 0.94;
            }
            @to
            {
                $PipelineCache.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
            {
                $PipelineHit.Opacity = 0.24;
            }
            @to
            {
                $PipelineHit.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineHit.Scale = 0.94;
            }
            @to
            {
                $PipelineHit.Scale = 1;
            }
        }
    }
    @parallel
    {
        @animate with Tween(150ms, EaseOut)
        {
            @from
