                $PipelineBackend.Opacity = 0.24;
            }
            @to
            {
                $PipelineBackend.Opacity = 1;
            }
        }
        @animate with Spring(700, 45)
        {
            @from
            {
                $PipelineBackend.Scale = 0.94;
            }
            @to
            {
                $PipelineBackend.Scale = 1;
            }
        }
    }
}

UserControl.Resources.Aspect:
@handle Playback;
@when $self.Visibility
{
    @if value == Visible
    {
        @parallel
        {
            @run $PipelineReplay as Playback;
            @animate with Tween(360ms, EaseOut)
            {
                @from
                {
                    Opacity = 0.25;
                }
                @to
                {
                    Opacity = 1;
                }
            }
            @animate with Spring(460, 38)
            {
                @from
                {
                    TranslateY = 18;
                }
                @to
                {
                    TranslateY = 0;
                }
            }
        }
    }
    @if value == Collapsed
    {
        @cancel Playback;
    }
}
@when $RunPipelineButton.IsPressed
{
    @run $PipelineReplay as Playback;
}
